import argparse
import base64
import json
import os
import socket
import threading
from dataclasses import dataclass
from typing import Dict, Iterable, List, Optional, Tuple
from urllib.parse import urlsplit, urlunsplit


DEFAULT_CONFIG = {
    "user": "Estudiante",
    "blocked": [
        "http://www.dcc.uchile.cl/",
        "http://cc4303.bachmann.cl/secret",
    ],
    "forbidden_words": [
        {"proxy": "[REDACTED]"},
        {"DCC": "[FORBIDDEN]"},
        {"biblioteca": "[???]"},
    ],
}

DEFAULT_HOME_HTML = """<!doctype html>
<html>
  <head><meta charset=\"utf-8\"><title>Proxy</title></head>
  <body>
    <h1>Proxy activo</h1>
    <p>Este servidor responde a requests HTTP y también puede actuar como proxy.</p>
  </body>
</html>
"""

BLOCKED_CAT_SVG = """<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"240\" height=\"180\" viewBox=\"0 0 240 180\">
  <rect width=\"240\" height=\"180\" fill=\"#fff4db\"/>
  <circle cx=\"120\" cy=\"100\" r=\"42\" fill=\"#444\"/>
  <polygon points=\"88,70 100,35 122,68\" fill=\"#444\"/>
  <polygon points=\"152,70 140,35 118,68\" fill=\"#444\"/>
  <circle cx=\"105\" cy=\"95\" r=\"5\" fill=\"#fff\"/>
  <circle cx=\"135\" cy=\"95\" r=\"5\" fill=\"#fff\"/>
  <path d=\"M112 112 Q120 120 128 112\" stroke=\"#fff\" stroke-width=\"4\" fill=\"none\" stroke-linecap=\"round\"/>
  <path d=\"M60 110 C75 100 85 100 98 108\" stroke=\"#444\" stroke-width=\"4\" fill=\"none\" stroke-linecap=\"round\"/>
  <path d=\"M142 108 C155 100 165 100 180 110\" stroke=\"#444\" stroke-width=\"4\" fill=\"none\" stroke-linecap=\"round\"/>
  <text x=\"120\" y=\"160\" font-size=\"18\" text-anchor=\"middle\" fill=\"#444\">Access denied</text>
</svg>
"""

BLOCKED_CAT_DATA_URI = "data:image/svg+xml;base64," + base64.b64encode(BLOCKED_CAT_SVG.encode("utf-8")).decode("ascii")


HTTP_METHODS_WITHOUT_BODY = {"GET", "HEAD", "DELETE", "OPTIONS", "TRACE"}
TEXTUAL_CONTENT_TYPES = ("text/", "application/json", "application/javascript", "application/xml", "+json", "+xml", "html")


@dataclass
class ParsedHTTPMessage:
    start_line: Dict[str, str]
    headers: List[Tuple[str, str]]
    body: str

    @property
    def header_map(self) -> Dict[str, str]:
        return {name.lower(): value for name, value in self.headers}


def parse_HTTP_message(http_message):
    """Parsea un mensaje HTTP a una estructura fácil de usar."""
    if isinstance(http_message, bytes):
        http_message = http_message.decode("latin-1")

    head, body = _split_http_message(http_message)
    lines = head.split("\r\n") if head else [""]
    start_line_raw = lines[0] if lines else ""
    headers = _parse_header_lines(lines[1:])

    if start_line_raw.startswith("HTTP/"):
        parts = start_line_raw.split(" ", 2)
        start_line = {
            "type": "response",
            "version": parts[0] if len(parts) > 0 else "HTTP/1.1",
            "status_code": parts[1] if len(parts) > 1 else "200",
            "reason": parts[2] if len(parts) > 2 else "OK",
            "raw": start_line_raw,
        }
    else:
        parts = start_line_raw.split(" ", 2)
        start_line = {
            "type": "request",
            "method": parts[0] if len(parts) > 0 and parts[0] else "GET",
            "target": parts[1] if len(parts) > 1 else "/",
            "version": parts[2] if len(parts) > 2 else "HTTP/1.1",
            "raw": start_line_raw,
        }

    return {
        "start_line": start_line,
        "headers": headers,
        "header_map": {name.lower(): value for name, value in headers},
        "body": body,
    }


def create_HTTP_message(http_data):
    """Convierte la estructura creada por parse_HTTP_message a un mensaje HTTP."""
    if isinstance(http_data, ParsedHTTPMessage):
        http_data = {
            "start_line": http_data.start_line,
            "headers": http_data.headers,
            "body": http_data.body,
        }

    start_line = http_data.get("start_line", {})
    if isinstance(start_line, str):
        first_line = start_line
    elif start_line.get("type") == "response":
        first_line = f"{start_line.get('version', 'HTTP/1.1')} {start_line.get('status_code', '200')} {start_line.get('reason', 'OK')}"
    else:
        first_line = f"{start_line.get('method', 'GET')} {start_line.get('target', '/')} {start_line.get('version', 'HTTP/1.1')}"

    headers = http_data.get("headers", [])
    if isinstance(headers, dict):
        headers = list(headers.items())

    header_lines = [f"{name}: {value}" for name, value in headers]
    body = http_data.get("body", "")
    if isinstance(body, bytes):
        body = body.decode("latin-1")

    if header_lines:
        return first_line + "\r\n" + "\r\n".join(header_lines) + "\r\n\r\n" + body
    return first_line + "\r\n\r\n" + body


def load_config(config_path: str) -> Dict:
    if not config_path or not os.path.exists(config_path):
        return dict(DEFAULT_CONFIG)
    with open(config_path, "r", encoding="utf-8") as file:
        data = json.load(file)
    config = dict(DEFAULT_CONFIG)
    config.update(data)
    config.setdefault("user", DEFAULT_CONFIG["user"])
    config.setdefault("blocked", [])
    config.setdefault("forbidden_words", [])
    return config


def _split_http_message(message: str) -> Tuple[str, str]:
    separator = "\r\n\r\n"
    index = message.find(separator)
    if index == -1:
        return message, ""
    return message[:index], message[index + len(separator) :]


def _parse_header_lines(lines: Iterable[str]) -> List[Tuple[str, str]]:
    headers = []
    for line in lines:
        if not line:
            continue
        if ":" not in line:
            continue
        name, value = line.split(":", 1)
        headers.append((name.strip(), value.lstrip()))
    return headers


def _headers_to_dict(headers: Iterable[Tuple[str, str]]) -> Dict[str, str]:
    return {name.lower(): value for name, value in headers}


def _dict_to_headers(headers: Dict[str, str]) -> List[Tuple[str, str]]:
    return list(headers.items())


def _canonical_url_from_parts(scheme: str, host: str, port: Optional[int], path: str, query: str = "") -> str:
    netloc = host.lower()
    if port and port != 80:
        netloc = f"{netloc}:{port}"
    normalized_path = path or "/"
    return urlunsplit((scheme.lower(), netloc, normalized_path, query, ""))


def _normalize_candidate_url(url: str) -> str:
    parsed = urlsplit(url)
    port = parsed.port
    if port is None:
        if parsed.scheme.lower() == "http":
            port = 80
    host = parsed.hostname or ""
    return _canonical_url_from_parts(parsed.scheme or "http", host, port, parsed.path, parsed.query)


def _build_full_url_from_request(parsed_request: Dict) -> str:
    start_line = parsed_request["start_line"]
    headers = parsed_request.get("header_map", {})
    target = start_line.get("target", "/")

    if target.startswith("http://") or target.startswith("https://"):
        return _normalize_candidate_url(target)

    host = headers.get("host", "")
    if not host:
        return _canonical_url_from_parts("http", "localhost", 80, target)

    if ":" in host:
        host_name, port_text = host.rsplit(":", 1)
        try:
            port = int(port_text)
        except ValueError:
            host_name, port = host, 80
    else:
        host_name, port = host, 80

    path = target or "/"
    if not path.startswith("/"):
        path = "/" + path
    return _canonical_url_from_parts("http", host_name, port, path)


def _is_blocked(url: str, blocked_list: Iterable[str]) -> bool:
    candidate = _normalize_candidate_url(url)
    candidate_parts = urlsplit(candidate)
    candidate_path = candidate_parts.path or "/"

    for blocked in blocked_list:
        blocked_norm = _normalize_candidate_url(blocked)
        blocked_parts = urlsplit(blocked_norm)
        blocked_path = blocked_parts.path or "/"
        same_origin = (
            candidate_parts.scheme == blocked_parts.scheme
            and candidate_parts.hostname == blocked_parts.hostname
            and (candidate_parts.port or 80) == (blocked_parts.port or 80)
        )
        if not same_origin:
            continue
        if candidate_path == blocked_path:
            return True
        if blocked_path.endswith("/") and candidate_path.startswith(blocked_path):
            return True
        if not blocked_path.endswith("/") and candidate_path.startswith(blocked_path + "/"):
            return True
    return False


def _is_textual_response(headers: Dict[str, str]) -> bool:
    content_type = headers.get("content-type", "").lower()
    return any(token in content_type for token in TEXTUAL_CONTENT_TYPES)


def _replace_forbidden_words(text: str, forbidden_words: Iterable[Dict[str, str]]) -> str:
    for item in forbidden_words:
        for bad, replacement in item.items():
            text = text.replace(bad, replacement)
    return text


def _build_local_response(status_code: int, reason: str, body: str, user: str, content_type: str = "text/html; charset=utf-8") -> bytes:
    headers = [
        ("HTTP/1.1", None),
    ]
    response_headers = [
        ("Content-Type", content_type),
        ("Content-Length", str(len(body.encode("utf-8")))),
        ("Connection", "close"),
        ("X-ElQuePregunta", user),
    ]
    start_line = f"HTTP/1.1 {status_code} {reason}"
    message = start_line + "\r\n" + "\r\n".join(f"{name}: {value}" for name, value in response_headers) + "\r\n\r\n" + body
    return message.encode("utf-8")


def _build_blocked_body(url: str) -> str:
    return f"""<!doctype html>
<html>
  <head><meta charset=\"utf-8\"><title>403 Forbidden</title></head>
  <body>
    <h1>403 Forbidden</h1>
    <p>La dirección <code>{url}</code> está bloqueada.</p>
    <img src=\"{BLOCKED_CAT_DATA_URI}\" alt=\"blocked cat\" />
  </body>
</html>
"""


def _build_home_body(user: str) -> str:
    return DEFAULT_HOME_HTML.replace("Proxy", f"Proxy ({user})")


def _add_or_replace_header(headers: List[Tuple[str, str]], header_name: str, header_value: str) -> List[Tuple[str, str]]:
    result = []
    replaced = False
    for name, value in headers:
        if name.lower() == header_name.lower():
            if not replaced:
                result.append((header_name, header_value))
                replaced = True
        else:
            result.append((name, value))
    if not replaced:
        result.append((header_name, header_value))
    return result


def _remove_headers(headers: List[Tuple[str, str]], names: Iterable[str]) -> List[Tuple[str, str]]:
    names_lower = {name.lower() for name in names}
    return [(name, value) for name, value in headers if name.lower() not in names_lower]


def _origin_request_message(parsed_request: Dict, user: str) -> bytes:
    start_line = parsed_request["start_line"]
    headers = list(parsed_request.get("headers", []))
    header_map = parsed_request.get("header_map", {})
    target = start_line.get("target", "/")

    if target.startswith("http://") or target.startswith("https://"):
        parsed_target = urlsplit(target)
        path = parsed_target.path or "/"
        if parsed_target.query:
            path = path + "?" + parsed_target.query
        start_line = dict(start_line)
        start_line["target"] = path

    headers = _add_or_replace_header(headers, "X-ElQuePregunta", user)
    headers = _add_or_replace_header(headers, "Connection", "close")
    headers = _add_or_replace_header(headers, "Proxy-Connection", "close")
    headers = _add_or_replace_header(headers, "Accept-Encoding", "identity")
    headers = _remove_headers(headers, ["Keep-Alive", "TE", "Trailer", "Upgrade"])

    message = create_HTTP_message({"start_line": start_line, "headers": headers, "body": parsed_request.get("body", "")})
    return message.encode("latin-1")


def _read_until(sockt: socket.socket, marker: bytes, buff_size: int) -> bytes:
    data = bytearray()
    while marker not in data:
        chunk = sockt.recv(buff_size)
        if not chunk:
            break
        data.extend(chunk)
    return bytes(data)


def receive_full_http_message(sockt: socket.socket, buff_size: int, is_request: bool = True) -> bytes:
    """Recibe un mensaje HTTP completo aunque el buffer sea menor al tamaño total."""
    data = bytearray()
    separator = b"\r\n\r\n"

    while separator not in data:
        chunk = sockt.recv(buff_size)
        if not chunk:
            return bytes(data)
        data.extend(chunk)

    head, body = bytes(data).split(separator, 1)
    parsed_head = parse_HTTP_message(head.decode("latin-1") + "\r\n\r\n")
    headers = parsed_head["header_map"]

    content_length = headers.get("content-length")
    transfer_encoding = headers.get("transfer-encoding", "").lower()

    if content_length is not None:
        try:
            expected_length = int(content_length)
        except ValueError:
            expected_length = 0
        while len(body) < expected_length:
            chunk = sockt.recv(buff_size)
            if not chunk:
                break
            body += chunk
        body = body[:expected_length]
    elif "chunked" in transfer_encoding:
        while True:
            if b"\r\n0\r\n" in body or body.endswith(b"\r\n0\r\n\r\n"):
                break
            chunk = sockt.recv(buff_size)
            if not chunk:
                break
            body += chunk
    else:
        if is_request:
            method = parsed_head["start_line"].get("method", "GET").upper()
            if method not in HTTP_METHODS_WITHOUT_BODY:
                while True:
                    chunk = sockt.recv(buff_size)
                    if not chunk:
                        break
                    body += chunk
        else:
            while True:
                chunk = sockt.recv(buff_size)
                if not chunk:
                    break
                body += chunk

    return head + separator + body


def _decode_chunked_body(chunked_body: bytes) -> bytes:
    idx = 0
    decoded = bytearray()
    total_len = len(chunked_body)

    while idx < total_len:
        line_end = chunked_body.find(b"\r\n", idx)
        if line_end == -1:
            break
        size_line = chunked_body[idx:line_end].split(b";", 1)[0].strip()
        try:
            size = int(size_line, 16)
        except ValueError:
            break
        idx = line_end + 2
        if size == 0:
            break
        decoded.extend(chunked_body[idx : idx + size])
        idx += size
        if chunked_body[idx : idx + 2] == b"\r\n":
            idx += 2
        else:
            break
    return bytes(decoded)


def _rebuild_response_with_modified_body(response_bytes: bytes, user: str, forbidden_words: Iterable[Dict[str, str]]) -> bytes:
    response_text = response_bytes.decode("latin-1")
    head, body = _split_http_message(response_text)
    parsed = parse_HTTP_message(head + "\r\n\r\n")
    headers = parsed["headers"]
    header_map = parsed["header_map"]

    body_bytes = body.encode("latin-1")
    if "chunked" in header_map.get("transfer-encoding", "").lower():
        body_bytes = _decode_chunked_body(body_bytes)
        headers = _remove_headers(headers, ["Transfer-Encoding"])

    if _is_textual_response(header_map):
        body_text = body_bytes.decode("latin-1")
        body_text = _replace_forbidden_words(body_text, forbidden_words)
        body_bytes = body_text.encode("latin-1")
        headers = _remove_headers(headers, ["Content-Length"])
        headers = _add_or_replace_header(headers, "Content-Length", str(len(body_bytes)))

    headers = _add_or_replace_header(headers, "X-ElQuePregunta", user)
    headers = _add_or_replace_header(headers, "Connection", "close")

    new_response = create_HTTP_message({
        "start_line": parsed["start_line"],
        "headers": headers,
        "body": body_bytes.decode("latin-1"),
    })
    return new_response.encode("latin-1")


def _maybe_return_local_page(request_data: Dict, config: Dict) -> Optional[bytes]:
    start_line = request_data["start_line"]
    headers = request_data.get("header_map", {})
    target_url = _build_full_url_from_request(request_data)
    host = headers.get("host", "")

    is_local_host = host.startswith("localhost") or host.startswith("127.0.0.1") or host.startswith("[::1]")
    if target_url in {"http://localhost:8000/", "http://127.0.0.1:8000/"}:
        method = start_line.get("method", "GET").upper()
        body = _build_home_body(config.get("user", DEFAULT_CONFIG["user"]))
        if method == "HEAD":
            body = ""
        return _build_local_response(200, "OK", body, config.get("user", DEFAULT_CONFIG["user"]))

    if is_local_host and target_url.endswith(":8000/"):
        method = start_line.get("method", "GET").upper()
        body = _build_home_body(config.get("user", DEFAULT_CONFIG["user"]))
        if method == "HEAD":
            body = ""
        return _build_local_response(200, "OK", body, config.get("user", DEFAULT_CONFIG["user"]))

    return None


def handle_client(client_socket: socket.socket, client_address, config: Dict, recv_buffer: int):
    try:
        raw_request = receive_full_http_message(client_socket, recv_buffer, is_request=True)
        if not raw_request:
            return

        request_data = parse_HTTP_message(raw_request)
        target_url = _build_full_url_from_request(request_data)
        method = request_data["start_line"].get("method", "GET").upper()

        local_response = _maybe_return_local_page(request_data, config)
        if local_response is not None:
            client_socket.sendall(local_response)
            return

        if _is_blocked(target_url, config.get("blocked", [])):
            body = _build_blocked_body(target_url)
            if method == "HEAD":
                body = ""
            response = _build_local_response(403, "Forbidden", body, config.get("user", DEFAULT_CONFIG["user"]))
            client_socket.sendall(response)
            return

        upstream_request = _origin_request_message(request_data, config.get("user", DEFAULT_CONFIG["user"]))
        target_parts = urlsplit(target_url)
        host = target_parts.hostname or request_data["header_map"].get("host", "")
        port = target_parts.port or 80

        if not host:
            body = _build_home_body(config.get("user", DEFAULT_CONFIG["user"]))
            response = _build_local_response(200, "OK", body if method != "HEAD" else "", config.get("user", DEFAULT_CONFIG["user"]))
            client_socket.sendall(response)
            return

        with socket.create_connection((host, port), timeout=15) as upstream_socket:
            upstream_socket.sendall(upstream_request)
            raw_response = receive_full_http_message(upstream_socket, recv_buffer, is_request=False)

        if not raw_response:
            response = _build_local_response(502, "Bad Gateway", "<h1>502 Bad Gateway</h1>", config.get("user", DEFAULT_CONFIG["user"]))
            client_socket.sendall(response)
            return

        if method == "HEAD":
            # En HEAD no se envía body al cliente, aunque el servidor lo haya enviado.
            head_only = raw_response.split(b"\r\n\r\n", 1)[0] + b"\r\n\r\n"
            parsed_response = parse_HTTP_message(head_only.decode("latin-1"))
            headers = _add_or_replace_header(parsed_response["headers"], "X-ElQuePregunta", config.get("user", DEFAULT_CONFIG["user"]))
            rebuilt = create_HTTP_message({"start_line": parsed_response["start_line"], "headers": headers, "body": ""})
            client_socket.sendall(rebuilt.encode("latin-1"))
            return

        modified_response = _rebuild_response_with_modified_body(raw_response, config.get("user", DEFAULT_CONFIG["user"]), config.get("forbidden_words", []))
        client_socket.sendall(modified_response)
    except Exception as exc:
        fallback = _build_local_response(500, "Internal Server Error", f"<pre>{exc}</pre>", config.get("user", DEFAULT_CONFIG["user"]))
        try:
            client_socket.sendall(fallback)
        except Exception:
            pass
    finally:
        try:
            client_socket.close()
        except Exception:
            pass


def run_proxy(host: str, port: int, config_path: str, recv_buffer: int):
    config = load_config(config_path)
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind((host, port))
    server_socket.listen(32)

    print(f"Proxy escuchando en {host}:{port}")
    print(f"Configuración: {config_path if config_path else 'por defecto'}")
    print(f"Buffer de recepción: {recv_buffer}")

    try:
        while True:
            client_socket, client_address = server_socket.accept()
            worker = threading.Thread(
                target=handle_client,
                args=(client_socket, client_address, config, recv_buffer),
                daemon=True,
            )
            worker.start()
    finally:
        server_socket.close()


def main():
    parser = argparse.ArgumentParser(description="Proxy HTTP para CC4303")
    parser.add_argument("config", nargs="?", default="proxy_config.json", help="Ruta al archivo JSON de configuración")
    parser.add_argument("--host", default="localhost", help="Host donde escucha el proxy")
    parser.add_argument("--port", type=int, default=8000, help="Puerto donde escucha el proxy")
    parser.add_argument("--recv-buffer", type=int, default=4096, help="Tamaño del buffer de recepción")
    args = parser.parse_args()

    run_proxy(args.host, args.port, args.config, args.recv_buffer)


if __name__ == "__main__":
    main()

